fountain Counter {
  drink mut count: Int = 0;
  glass increment() -> Void {
    drip count;
  }
  glass value() -> Int {
    return count;
  }
}
glass main() -> Int {
  drink c: Any = new Counter();
  c.increment();
  c.increment();
  pour(c.value());
  return 0;
}

fountain Point {
  drink x: Int = 0;
  drink y: Int = 0;
  glass init(px: Int, py: Int) -> Void {
    x = px;
    y = py;
  }
}
glass main() -> Int {
  drink p: Any = new Point();
  p.init(3, 4);
  pour(p.x);
  pour(p.y);
  return 0;
}

glass sum_tail(n: Int, acc: Int) -> Int {
  thirsty (n <= 0) {
    return acc;
  }
  return sum_tail(n - 1, acc + n);
}
glass main() -> Int {
  pour(sum_tail(100, 0));
  return 0;
}

glass is_positive(x: Int) -> Bool {
  return x > 0;
}
glass main() -> Int {
  drink xs: Reservoir[Int] = [-1, 2, -3, 4];
  drink pos: Reservoir[Int] = strain(xs, is_positive);
  pour(size(pos));
  return 0;
}

glass inc(x: Int) -> Int { return x + 1; }
glass dbl(x: Int) -> Int { return x * 2; }
glass main() -> Int {
  pour(3 |> inc |> dbl);
  return 0;
}

glass main() -> Int {
  drink v: Any = 42;
  drink n: Any = thirst v quench;
  pour(n);
  return 0;
}

fountain Acc {
  drink mut total: Int = 0;
  glass add(n: Int) -> Void { total += n; }
  glass result() -> Int { return total; }
}
glass main() -> Int {
  drink a: Any = new Acc();
  a.add(10);
  a.add(20);
  a.add(30);
  pour(a.result());
  return 0;
}

glass main() -> Int {
  refill 5 times {
    pour("line");
  }
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3, 4, 5];
  drink s: Int = distill(xs, 0, glass(acc: Int, x: Int) -> Int { return acc + x; });
  pour(s);
  return 0;
}

glass main() -> Int {
  drink parts: Reservoir[String] = split("a:b:c", ":");
  drink joined: String = distill(parts, "", glass(acc: String, x: String) -> String { return acc + x; });
  pour(joined);
  return 0;
}

glass main() -> Int {
  drink mut x: Int = 0;
  drip x 5;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink mut x: Int = 10;
  x += 5;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [];
  pour(size(xs));
  return 0;
}

glass main() -> Int {
  drink x: Bool = quenched and parched;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink x: Bool = parched or quenched;
  pour(x);
  return 0;
}

glass grade(n: Int) -> String {
  thirsty (n >= 90) {
    return "A";
  } hydrated {
    thirsty (n >= 80) {
      return "B";
    } hydrated {
      return "C";
    }
  }
}
glass main() -> Int {
  pour(grade(95));
  pour(grade(85));
  pour(grade(70));
  return 0;
}

glass make_adder(n: Int) -> Any {
  return glass(x: Int) -> Int { return x + n; };
}
glass main() -> Int {
  drink add5: Any = make_adder(5);
  pour(add5(10));
  return 0;
}

glass main() -> Int {
  pour(1);
  pour(2);
  pour(3);
  return 0;
}

glass outer() -> Int {
  drink mut x: Int = 10;
  glass inner() -> Int {
    return 99;
  }
  return inner();
}
glass main() -> Int {
  pour(outer());
  return 0;
}

glass main() -> Int {
  drink s: String = "hello";
  pour(length(s));
  return 0;
}

glass main() -> Int {
  drink x: Any = empty;
  drink y: Any = x?.nonexistent;
  pour(y == empty);
  return 0;
}

glass main() -> Int {
  refill 0 times {
    pour("never");
  }
  pour("done");
  return 0;
}

glass main() -> Int {
  drink ns: Reservoir[Int] = [1, 2, 3];
  drink strs: Reservoir[Any] = transmute(ns, glass(x: Int) -> String { return "item"; });
  pour(size(strs));
  return 0;
}

import "thirst::json" as json;
glass main() -> Int {
  drink obj: Any = json.parse("{\"x\": 42}");
  drink val: Any = json.get(obj, "x");
  pour(val);
  return 0;
}

glass main() -> Int {
  pour(1 < 2);
  pour(2 <= 2);
  pour(3 >= 3);
  pour(4 > 3);
  return 0;
}
